async def restart_astrohub() -> dict:
    """v7.114: е№ІеҮҖйҮҚеҗҜ - зӢ¬з«Ӣи„ҡжң¬зӯүз«ҜеҸЈйҮҠж”ҫеҗҺеҗҜеҠЁж–°иҝӣзЁӢ,sys.exit и§ҰеҸ‘ graceful shutdown."""
    import subprocess
    import os
    import sys

    cwd = os.getcwd()
    python_exe = sys.executable

    helper = os.path.join(cwd, "src", "main", "restart_helper.py")
    subprocess.Popen(
        [python_exe, helper, "127.0.0.1", "10280", python_exe, cwd],
        cwd=cwd,
        creationflags=subprocess.CREATE_NO_WINDOW if hasattr(subprocess, "CREATE_NO_WINDOW") else 0,
