@api_router.post("/vision/region-analyze", summary="жЎҶйҖүеҢәеҹҹеҲҶжһҗ", tags=["Vision"])
async def region_analyze(req: RegionAnalyzeRequest) -> dict:
    """еҲҶжһҗжЎҶйҖүеҢәеҹҹ: зҷҪе№іиЎЎдҝ®жӯЈйҮҸ + еҸҚе·®еҖјгҖӮ"""
    from src.vision.region_analyzer import analyze_whitebalance, calc_contrast
    try:
        bgr = _decode_image(req.image_base64)
        if bgr is None or bgr.size == 0:
            return {"success": False, "message": "еӣҫеғҸи§Јз ҒеӨұиҙҘ"}
    except Exception as e:
        return {"success": False, "message": f"еӣҫеғҸи§Јз ҒејӮеёё: {e}"}

    result = {"success": True}
    if req.action in ("whitebalance", "both"):
        result["whitebalance"] = analyze_whitebalance(bgr)
    if req.action in ("focus", "both"):
        result["contrast"] = round(calc_contrast(bgr), 2)
    return result


@api_router.post("/vision/whitebalance-apply", summary="еә”з”ЁзҷҪе№іиЎЎдҝ®жӯЈ", tags=["Vision"])
async def whitebalance_apply(data: dict) -> dict:
    """еҶҷе…ҘзҷҪе№іиЎЎеҲ° ISAPIгҖӮ{"device_id": str, "red_gain": int, "blue_gain": int}"""
    import xml.etree.ElementTree as ET
    mgr: PTZDeviceController | None = _managers.get("ptz_controller")
