        return {"success": False, "message": "PTZжҺ§еҲ¶еҷЁжңӘеҲқе§ӢеҢ–"}

    client, err = _get_client_for_device(mgr, data.get("device_id", ""))
    if err:
        return {"success": False, "message": err}

