@api_router.post("/vision/focus-search", summary="еҸҚе·®еҜ№з„Ұжҗңзҙў", tags=["Vision"])
async def focus_search(data: dict) -> dict:
    """жЎҶйҖүеҢәеҹҹеҸҚе·®еҜ№з„ҰгҖӮ{"device_id": str, "image_base64": str}"""
    from src.vision.region_analyzer import ContrastAF, calc_contrast

    mgr: PTZDeviceController | None = _managers.get("ptz_controller")
    if not mgr:
        return {"success": False, "message": "PTZжҺ§еҲ¶еҷЁжңӘеҲқе§ӢеҢ–"}

    client, err = _get_client_for_device(mgr, data.get("device_id", ""))
    if err:
        return {"success": False, "message": err}

    ctrl, _ = mgr._get_controller(_resolve_device_id_to_ip(mgr, data.get("device_id", "")))
    if not ctrl:
        return {"success": False, "message": "PTZ controller not found"}

    af = ContrastAF(step_size=5, min_step=1)
    try:
        bgr = _decode_image(data["image_base64"])
        if bgr is None:
            return {"success": False, "message": "еӣҫеғҸи§Јз ҒеӨұиҙҘ"}
    except Exception as e:
        return {"success": False, "message": f"еӣҫеғҸи§Јз ҒејӮеёё: {e}"}

    steps_log = []
    for i in range(20):
        cmd = af.step(bgr)
        steps_log.append({"step": i, "contrast": cmd["contrast"],
                           "action": cmd["action"], "message": cmd["message"]})
        if cmd["action"] == "stop":
            break

        speed = cmd["step"]
        if cmd["action"] == "focus_far":
            ctrl.continuous_move(pan=0, tilt=0, zoom=0, focus=speed)
        else:
            ctrl.continuous_move(pan=0, tilt=0, zoom=0, focus=-speed)

        time.sleep(0.3)
        ctrl.stop_move()
        time.sleep(0.2)

        try:
            jpg = client.capture_picture()
            if jpg:
                arr = np.frombuffer(jpg, np.uint8)
                bgr = cv2.imdecode(arr, cv2.IMREAD_COLOR)
                if bgr is None:
                    break
            else:
                break
        except Exception:
            break

    final_contrast = calc_contrast(bgr) if bgr is not None else 0
    return {"success": True, "steps": steps_log,
            "final_contrast": round(final_contrast, 2), "total_steps": len(steps_log)}


@api_router.post("/vision/stack-start", summary="еҗҜеҠЁжҳҹзӮ№еҸ еҠ ", tags=["Vision"])
async def stack_start(req: StackStartRequest) -> dict:
    """еҗҜеҠЁжҳҹзӮ№еҸ еҠ дјҡиҜқгҖӮ"""
    global _stack_engine, _stack_task
    mgr: PTZDeviceController | None = _managers.get("ptz_controller")
    if not mgr:
        return {"success": False, "message": "PTZжҺ§еҲ¶еҷЁжңӘеҲқе§ӢеҢ–"}

    client, err = _get_active_client(mgr)
    if err:
        return {"success": False, "message": err}

    total_frames = int(req.total_exposure * 1000 / req.frame_exposure_ms)
    if total_frames < 2:
        return {"success": False, "message": f"жҖ»её§ж•°еӨӘе°‘: {total_frames}"}

    from src.vision.stack_engine import StackEngine
    _stack_engine = StackEngine(client)
    _stack_engine.start(total_frames)

    connected = mgr.get_connected_device()
    target_ip = connected["ip"]
    _stack_task = asyncio.create_task(
        _run_stack_collection(mgr, target_ip, req.frame_exposure_ms, total_frames))

    return {"success": True, "total_frames": total_frames,
            "frame_exposure_ms": req.frame_exposure_ms, "total_exposure_s": req.total_exposure}


async def _run_stack_collection(mgr, target_ip: str, exposure_ms: int, total_frames: int):
    global _stack_engine
    client, err = _get_client_for_device(mgr, target_ip)
    if err or not _stack_engine:
        return

    for i in range(total_frames):
        if not _stack_engine._running or _stack_engine._cancelled:
            break
        try:
            jpg = client.capture_picture()
            if not jpg:
                continue
            arr = np.frombuffer(jpg, np.uint8)
            bgr = cv2.imdecode(arr, cv2.IMREAD_COLOR)
            if bgr is None:
                continue
            _stack_engine.add_frame(bgr)
        except Exception:
            continue
        await asyncio.sleep(exposure_ms / 1000.0)


@api_router.post("/vision/stack-stop", summary="еҒңжӯўжҳҹзӮ№еҸ еҠ ", tags=["Vision"])
async def stack_stop() -> dict:
    global _stack_engine, _stack_task
    if _stack_engine:
        result = _stack_engine.finish()
        _stack_engine = None
        _stack_task = None
        return result
    return {"success": False, "message": "ж— жҙ»и·ғеҸ еҠ дјҡиҜқ"}


