async def region_analyze(req: RegionAnalyzeRequest) -> dict:
    """еҲҶжһҗжЎҶйҖүеҢәеҹҹ: зҷҪе№іиЎЎдҝ®жӯЈйҮҸ + еҜ№жҜ”еәҰеҖјгҖӮ
    ж”ҜжҢҒдёӨз§ҚжЁЎејҸ:
    1. image_base64: зӣҙжҺҘеҲҶжһҗ base64 еӣҫзүҮ
    2. image_path + x/y/w/h: д»Һж–Үд»¶иЈҒеүӘеҗҺеҲҶжһҗ
    """
    from src.vision.region_analyzer import analyze_whitebalance, calc_contrast
    bgr = None
    if req.image_path:
        bgr = cv2.imread(req.image_path)
        if bgr is not None and req.w > 0 and req.h > 0:
            h, w = bgr.shape[:2]
            x1 = max(0, int(req.x * w))
            y1 = max(0, int(req.y * h))
            x2 = min(w, int((req.x + req.w) * w))
            y2 = min(h, int((req.y + req.h) * h))
            if x2 > x1 and y2 > y1:
                bgr = bgr[y1:y2, x1:x2]
    elif req.image_base64:
        try:
            bgr = _decode_image(req.image_base64)
        except Exception:
            pass
    if bgr is None or bgr.size == 0:
        return {"success": False, "message": "еӣҫеғҸи§Јз ҒеӨұиҙҘ"}

    result = {"success": True}
    if req.action in ("whitebalance", "both"):
        result["whitebalance"] = analyze_whitebalance(bgr)
    if req.action in ("focus", "both"):
        result["contrast"] = round(calc_contrast(bgr), 2)
    return result

