function _finishRegion() {
    var overlay = document.getElementById('regionOverlay');
    var box = document.getElementById('regionBox');
    var btnWB = document.getElementById('btnRegionWB');
    var btnAF = document.getElementById('btnRegionAF');
    // е°қиҜ•еӨҡз§Қж–№ејҸжүҫеҲ°и§Ҷйў‘ canvas
    var canvas = document.querySelector('#divPlugin canvas');
    if (!canvas) canvas = document.getElementById('divPlugin').querySelector('canvas');
    if (!canvas) canvas = document.querySelector('#divPlugin .play-window');
    if (!canvas) canvas = document.querySelector('#divPlugin canvas.play-window');
    if (!canvas) {
        _finishRegionViaApi();
        return;
    }

    var ow = overlay.offsetWidth, oh = overlay.offsetHeight;
    var cw = canvas.width, ch = canvas.height;
    var sx = parseInt(box.style.left) / ow * cw;
    var sy = parseInt(box.style.top) / oh * ch;
    var sw = parseInt(box.style.width) / ow * cw;
    var sh = parseInt(box.style.height) / oh * ch;
    if (sw < 5 || sh < 5) { showToast('warning', 'жЎҶйҖүеҢәеҹҹеӨӘе°Ҹ'); return; }

    var tmp = document.createElement('canvas');
    tmp.width = sw; tmp.height = sh;
    tmp.getContext('2d').drawImage(canvas, sx, sy, sw, sh, 0, 0, sw, sh);
    var b64 = tmp.toDataURL('image/jpeg', 0.85);

    var deviceId = window.connectedDevice.ip;
    if (_regionMode === 'whitebalance') {
        apiPost('/api/v1/vision/region-analyze', { image_base64: b64, action: 'whitebalance' })
            .then(function(r) {
                if (!r || !r.success) { showToast('error', 'еҲҶжһҗеӨұиҙҘ'); return; }
                var wb = r.whitebalance;
                apiPost('/api/v1/vision/whitebalance-apply', {
                    device_id: deviceId, red_gain: wb.red_gain, blue_gain: wb.blue_gain
                }).then(function(r2) {
                    showToast(r2.success ? 'success' : 'error',
                        r2.success ? 'зҷҪе№іиЎЎе·Іеә”з”Ё R=' + wb.red_gain + ' B=' + wb.blue_gain : r2.message);
                });
            }).catch(function(e) { showToast('error', 'ејӮеёё: ' + e.message); });
    } else if (_regionMode === 'focus') {
        showToast('info', 'еҸҚе·®еҜ№з„Ұдёӯ...');
        apiPost('/api/v1/vision/focus-search', { device_id: deviceId, image_base64: b64 })
            .then(function(r) {
                showToast(r.success ? 'success' : 'error',
                    r.success ? 'еҜ№з„Ұе®ҢжҲҗ (' + r.total_steps + 'жӯҘ, еҸҚе·®=' + r.final_contrast + ')' : r.message);
            }).catch(function(e) { showToast('error', 'ејӮеёё: ' + e.message); });
    }

    _regionMode = null;
    btnWB.className = 'btn btn-secondary btn-sm';
    btnAF.className = 'btn btn-secondary btn-sm';
    overlay.style.display = 'none';
    box.style.display = 'none';
}

