// v8.11: з»ҹдёҖ ISAPI жҲӘеӣҫ вҶ’ еҗҺз«ҜиЈҒеүӘ вҶ’ иҝӯд»Јжҗңзҙў вҶ’ ж“ҚдҪңж—Ҙеҝ—
function _finishRegion() {
    var overlay = document.getElementById('regionOverlay');
    var box = document.getElementById('regionBox');
    var dev = window.connectedDevice;
    if (!dev || !dev.ip) { showToast('error', 'жңӘиҝһжҺҘи®ҫеӨҮ'); _resetRegionUI(); return; }

    var ow = overlay.offsetWidth, oh = overlay.offsetHeight;
    var sx = parseInt(box.style.left) / ow;
    var sy = parseInt(box.style.top) / oh;
    var sw = parseInt(box.style.width) / ow;
    var sh = parseInt(box.style.height) / oh;
    if (sw < 0.01 || sh < 0.01) { showToast('warning', 'жЎҶйҖүеҢәеҹҹеӨӘе°Ҹ'); _resetRegionUI(); return; }

    var mode = _regionMode;
    var endpoint = mode === 'whitebalance' ? '/api/v1/vision/whitebalance-search'
                                           : '/api/v1/vision/focus-search';
    var label = mode === 'whitebalance' ? 'зҷҪе№іиЎЎ' : 'еҜ№з„Ұ';

    _resetRegionUI();
    showToast('info', label + 'иҝӯд»Јдёӯ...');
    addLog('info', 'в”Җв”Җ ' + label + 'иҝӯд»ЈејҖе§Ӣ в”Җв”Җ');

    apiPost(endpoint, { x: sx, y: sy, w: sw, h: sh }).then(function(r) {
        if (!r || !r.success) {
            addLog('error', label + 'еӨұиҙҘ: ' + (r ? r.message : 'жңӘзҹҘй”ҷиҜҜ'));
            showToast('error', label + 'еӨұиҙҘ');
            return;
        }
        // жҳҫзӨәжҜҸдёҖжӯҘ
        var steps = r.steps || [];
        for (var i = 0; i < steps.length; i++) {
            var s = steps[i];
            if (s.type === 'start') {
                addLog('info', label + 'ејҖе§Ӣ, ' + s.crop);
            } else if (s.type === 'wb') {
                addLog('info', 'и°ғж•ҙ' + label + ' #' + s.step + ': ' + s.stage
                    + ' R=' + s.red_gain + ' B=' + s.blue_gain
                    + ' вҶ’ R=' + s.r_avg + ' G=' + s.g_avg + ' B=' + s.b_avg
                    + ' (delta=' + s.delta + ')');
            } else if (s.type === 'focus') {
                var dur = s.duration ? s.duration.toFixed(2) + 's' : '-';
                addLog('info', 'еҜ№з„Ұ #' + s.step + ': ' + s.action
                    + ' жҢҒз»ӯ=' + dur + ' еҸҚе·®=' + s.contrast
                    + ' [' + s.message + ']');
            } else if (s.type === 'cleanup') {
                addLog('info', 'жү§иЎҢжё…зҗҶ... ' + s.message);
            }
        }
        if (mode === 'whitebalance') {
            showToast('success', 'зҷҪе№іиЎЎе®ҢжҲҗ R=' + r.final_red + ' B=' + r.final_blue);
            addLog('success', 'в”Җв”Җ зҷҪе№іиЎЎе®ҢжҲҗ: R=' + r.final_red + ' B=' + r.final_blue + ' (' + r.total_steps + 'жӯҘ) в”Җв”Җ');
        } else {
            showToast('success', 'еҜ№з„Ұе®ҢжҲҗ еҸҚе·®=' + r.final_contrast + ' (' + r.total_steps + 'жӯҘ)');
            addLog('success', 'в”Җв”Җ еҜ№з„Ұе®ҢжҲҗ: еҸҚе·®=' + r.final_contrast + ' (' + r.total_steps + 'жӯҘ) в”Җв”Җ');
        }
    }).catch(function(e) {
        addLog('error', label + 'ејӮеёё: ' + e.message);
        showToast('error', 'ејӮеёё: ' + e.message);
    });
}

