    def _get_binary(self, endpoint: str) -> bytes | None:
        """д»Һ ISAPI з«ҜзӮ№иҺ·еҸ–дәҢиҝӣеҲ¶е“Қеә”пјҲз”ЁдәҺеӣҫзүҮ / и§Ҷйў‘ж–Үд»¶пјүгҖӮ"""
        url = f"{self.base_url}{endpoint}"
        LOG.log("info", f"ISAPI BINARY GET: {endpoint}")
        try:
            response = self.session.get(url, timeout=15)
            if response.status_code == 200:
                return response.content
            LOG.log("error", f"ISAPI binary GET еӨұиҙҘ: {endpoint} (status={response.status_code})")
            return None
        except requests.exceptions.Timeout:
            LOG.log("error", f"ISAPI binary GET и¶…ж—¶: {endpoint}")
            return None
        except Exception as e:
            LOG.log("error", f"ISAPI binary GET й”ҷиҜҜ: {endpoint}: {e}")
            return None

    def capture_picture(self, channel: int = 1) -> bytes | None:
        """йҖҡиҝҮ ISAPI зӣҙжҺҘд»Һж‘„еғҸеӨҙжҠ“еҸ– JPEG еӣҫзүҮгҖӮ

