@api_router.post("/vision/whitebalance-search", summary="зҷҪе№іиЎЎиҝӯд»Јжҗңзҙў", tags=["Vision"])
async def whitebalance_search(data: dict) -> dict:
    """зҷҪе№іиЎЎиҝӯд»ЈжҗңзҙўгҖӮ
    иҜ·жұӮ: {"x":0.1,"y":0.1,"w":0.3,"h":0.3}
    е“Қеә”: жҜҸжӯҘиҝӯд»Јж—Ҙеҝ— + жңҖз»Ҳ R/B еўһзӣҠеҖјгҖӮ
    """
    from src.vision.region_analyzer import IterativeWB

    mgr: PTZDeviceController | None = _managers.get("ptz_controller")
    if not mgr:
        return {"success": False, "message": "PTZжҺ§еҲ¶еҷЁжңӘеҲқе§ӢеҢ–"}

    connected = mgr.get_connected_device()
    if not connected:
        return {"success": False, "message": "ж— жҙ»и·ғи®ҫеӨҮ"}

    device_ip = connected["ip"]
    client, err = _get_client_for_device(mgr, device_ip)
    if err:
        return {"success": False, "message": err}

    x = float(data.get("x", 0))
    y = float(data.get("y", 0))
    w = float(data.get("w", 0))
    h = float(data.get("h", 0))

    if w <= 0 or h <= 0:
        return {"success": False, "message": "жЎҶйҖүеҢәеҹҹж— ж•Ҳ"}

    # еҲқе§ӢжҲӘеӣҫ+иЈҒеүӘ
    bgr, crop_path, info = _capture_and_crop(client, mgr, device_ip, "WB", x, y, w, h)
    if bgr is None:
        return {"success": False, "message": info.get("error", "жҲӘеӣҫеӨұиҙҘ")}

    wb = IterativeWB()
    steps_log = [{"step": 0, "type": "start",
                   "crop": f"X={info['crop_x1']}~{info['crop_x2']}, Y={info['crop_y1']}~{info['crop_y2']}, е…ұ{info['pixels']}еғҸзҙ "}]

    max_iter = 30
    for i in range(max_iter):
        cmd = wb.step(bgr)
        step_info = {
            "step": i + 1,
            "type": "wb",
            "stage": cmd["stage"],
            "step_size": cmd["step_size"],
            "red_gain": cmd["red_gain"],
            "blue_gain": cmd["blue_gain"],
            "r_avg": cmd["r_avg"],
            "g_avg": cmd["g_avg"],
            "b_avg": cmd["b_avg"],
            "delta": cmd["delta"],
            "message": cmd["message"],
        }
        steps_log.append(step_info)

        if cmd["action"] == "stop":
            break

        # еә”з”ЁеўһзӣҠеҲ°и®ҫеӨҮ
        _apply_whitebalance(client, cmd["red_gain"], cmd["blue_gain"])
        time.sleep(0.15)

        # йҮҚж–°жҲӘеӣҫ+иЈҒеүӘ
        bgr, crop_path, _ = _capture_and_crop(client, mgr, device_ip, "WB", x, y, w, h)
        if bgr is None:
            steps_log.append({"step": i + 1, "type": "error", "message": "жҲӘеӣҫеӨұиҙҘ"})
            break

    # жё…зҗҶ
    _cleanup_temp("WB", device_ip)
    steps_log.append({"step": len(steps_log), "type": "cleanup", "message": "жё…зҗҶе®ҢжҲҗ"})

    last_wb = steps_log[-2] if len(steps_log) >= 2 else {}
    return {"success": True, "steps": steps_log,
            "final_red": last_wb.get("red_gain", 100),
            "final_blue": last_wb.get("blue_gain", 100),
            "total_steps": len(steps_log)}


