function _finishRegion() {
    var overlay = document.getElementById('regionOverlay');
    var box = document.getElementById('regionBox');
    var dev = window.connectedDevice;
    if (!dev || !dev.ip) { showToast('error', 'жңӘиҝһжҺҘи®ҫеӨҮ'); _resetRegionUI(); return; }

    var ow = overlay.offsetWidth, oh = overlay.offsetHeight;
    var sx = parseInt(box.style.left) / ow;
    var sy = parseInt(box.style.top) / oh;
    var sw = parseInt(box.style.width) / ow;
    var sh = parseInt(box.style.height) / oh;
    if (sw < 0.01 || sh < 0.01) { showToast('warning', 'жЎҶйҖүеҢәеҹҹеӨӘе°Ҹ'); _resetRegionUI(); return; }

    var mode = _regionMode;
    var endpoint = mode === 'whitebalance' ? '/api/v1/vision/whitebalance-search'
                                           : '/api/v1/vision/focus-search';
    var label = mode === 'whitebalance' ? 'зҷҪе№іиЎЎ' : 'еҜ№з„Ұ';

    _resetRegionUI();
    showToast('info', label + 'иҝӯд»Јдёӯ...');
    operationLog('в”Җв”Җ ' + label + 'иҝӯд»ЈејҖе§Ӣ в”Җв”Җ', 'info');

    // SSE жөҒејҸи°ғз”Ё
    var body = JSON.stringify({ x: sx, y: sy, w: sw, h: sh });
    fetch(endpoint, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: body })
        .then(function(resp) {
            if (!resp.ok) throw new Error('HTTP ' + resp.status);
            var reader = resp.body.getReader();
            var decoder = new TextDecoder();
            var buf = '';
            function pump() {
                return reader.read().then(function(r) {
                    if (r.done) return;
                    buf += decoder.decode(r.value, { stream: true });
                    // жҢү \n\n еҲҶеүІдәӢд»¶
                    var parts = buf.split('\n\n');
                    buf = parts.pop();  // жңҖеҗҺдёҖж®өеҸҜиғҪдёҚе®Ңж•ҙ
                    for (var i = 0; i < parts.length; i++) {
                        var line = parts[i];
                        if (!line.startsWith('data: ')) continue;
                        try {
                            var ev = JSON.parse(line.slice(6));
                            if (ev.type === 'start') {
                                operationLog(label + 'ејҖе§Ӣ, ' + ev.crop, 'info');
                            } else if (ev.type === 'wb') {
                                operationLog('и°ғж•ҙ #' + ev.step + ': ' + ev.stage
                                    + ' R=' + ev.red_gain + ' B=' + ev.blue_gain
                                    + ' вҶ’ R=' + ev.r_avg + ' G=' + ev.g_avg + ' B=' + ev.b_avg
                                    + ' (О”=' + ev.delta + ')', 'debug');
                            } else if (ev.type === 'done') {
                                showToast('success', label + 'е®ҢжҲҗ R=' + ev.final_red + ' B=' + ev.final_blue);
                                operationLog('в”Җв”Җ ' + label + 'е®ҢжҲҗ: R=' + ev.final_red + ' B=' + ev.final_blue + ' (' + ev.total_steps + 'жӯҘ) в”Җв”Җ', 'success');
                            } else if (ev.type === 'cleanup') {
                                operationLog('жё…зҗҶе®ҢжҲҗ', 'info');
                            } else if (ev.type === 'error') {
                                operationLog(label + 'еӨұиҙҘ: ' + ev.message, 'error');
                                showToast('error', label + 'еӨұиҙҘ');
                            }
                        } catch(e) { /* и·іиҝҮжҚҹеқҸзҡ„ JSON */ }
                    }
                    return pump();
                });
            }
            return pump();
        })
        .catch(function(e) {
            operationLog(label + 'ејӮеёё: ' + e.message, 'error');
            showToast('error', 'ејӮеёё: ' + e.message);
        });

